'use client'
import { cn, createMachine, useMachine, useSignals } from '@cascivo/core'
import type { HTMLAttributes } from 'react'
import styles from './avatar.module.css'

const machine = createMachine({
  initial: 'loading' as const,
  states: {
    loading: { on: { LOADED: 'loaded', ERROR: 'error' } },
    loaded: {},
    error: {},
  },
})

export interface AvatarProps extends HTMLAttributes<HTMLSpanElement> {
  src?: string
  alt?: string
  fallback?: string
  size?: 'xs' | 'sm' | 'md' | 'lg' | 'xl'
  status?: 'online' | 'offline' | 'busy'
}

export function Avatar({
  src,
  alt = '',
  fallback,
  size = 'md',
  status,
  className,
  ...props
}: AvatarProps) {
  useSignals()
  const [state, send] = useMachine(machine)
  const showImage = Boolean(src) && state.value !== 'error'
  // Only expose role="img" when there's a name for it. A nameless avatar (no
  // alt, no fallback — e.g. a src that 404s in a static build) becomes
  // decorative instead of an unlabeled image (role-img-alt).
  const label = alt || fallback

  return (
    <span
      data-size={size}
      data-status={status}
      className={cn(styles['avatar'], className)}
      role={showImage || !label ? undefined : 'img'}
      aria-label={showImage ? undefined : label || undefined}
      {...props}
    >
      {showImage ? (
        <img
          className={styles['image']}
          src={src}
          alt={alt}
          onLoad={() => send('LOADED')}
          onError={() => send('ERROR')}
        />
      ) : (
        <span className={styles['fallback']} aria-hidden="true">
          {fallback}
        </span>
      )}
      {status && <span className={styles['status']} aria-hidden="true" />}
    </span>
  )
}

@layer cascivo.component {
  .avatar {
    position: relative;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    flex-shrink: 0;
    overflow: visible;
    border-radius: var(--cascivo-radius-full);
    background-color: var(--cascivo-color-accent-subtle);
    color: var(--cascivo-color-text);
    font-family: var(--cascivo-font-sans);
    font-weight: var(--cascivo-font-medium);
    user-select: none;

    &[data-size='xs'] {
      inline-size: 1.5rem;
      block-size: 1.5rem;
      font-size: var(--cascivo-text-xs);
    }
    &[data-size='sm'] {
      inline-size: 2rem;
      block-size: 2rem;
      font-size: var(--cascivo-text-xs);
    }
    &[data-size='md'] {
      inline-size: 2.5rem;
      block-size: 2.5rem;
      font-size: var(--cascivo-text-sm);
    }
    &[data-size='lg'] {
      inline-size: 3rem;
      block-size: 3rem;
      font-size: var(--cascivo-text-base);
    }
    &[data-size='xl'] {
      inline-size: 4rem;
      block-size: 4rem;
      font-size: var(--cascivo-text-lg);
    }
  }

  .image {
    inline-size: 100%;
    block-size: 100%;
    object-fit: cover;
    border-radius: inherit;
  }

  .fallback {
    line-height: 1;
    text-transform: uppercase;
  }

  .status {
    position: absolute;
    inset-block-end: 0;
    inset-inline-end: 0;
    inline-size: 28%;
    block-size: 28%;
    min-inline-size: 0.5rem;
    min-block-size: 0.5rem;
    border-radius: var(--cascivo-radius-full);
    border: 2px solid var(--cascivo-color-surface);

    .avatar[data-status='online'] & {
      background-color: var(--cascivo-color-success);
    }
    .avatar[data-status='offline'] & {
      background-color: var(--cascivo-color-text-muted);
    }
    .avatar[data-status='busy'] & {
      background-color: var(--cascivo-color-destructive);
    }
  }
}
